"""Task routes."""

from pyserver.db import Database
from pyserver.models.task import TaskStatus, task_from_row
from pyserver.utils.time import utc_now_iso
from pyserver.validators import validate_title


def list_tasks(db: Database, params: dict) -> list[dict]:
    """Return all tasks, optionally filtered by status."""
    status = params.get("status")
    if status:
        rows = db.fetch_all("SELECT * FROM tasks WHERE status = ?", (status,))
    else:
        rows = db.fetch_all("SELECT * FROM tasks")
    return [task_from_row(row).__dict__ for row in rows]


def create_task(db: Database, payload: dict) -> dict:
    """Create a new task from a JSON payload."""
    title = validate_title(payload["title"])
    cursor = db.execute(
        "INSERT INTO tasks (title, status, owner_id, created_at) VALUES (?, ?, ?, ?)",
        (title, TaskStatus.OPEN.value, payload.get("owner_id"), utc_now_iso()),
    )
    return {"id": cursor.lastrowid, "title": title}


def complete_task(db: Database, payload: dict) -> dict:
    """Mark a task as done."""
    task_id = payload["task_id"]
    db.execute(
        "UPDATE tasks SET status = ? WHERE id = ?",
        (TaskStatus.DONE.value, task_id),
    )
    return {"id": task_id, "status": TaskStatus.DONE.value}

"""Application wiring and entry point."""

from pyserver.config import Settings, load_config
from pyserver.db import Database
from pyserver.routes import register_routes


class App:
    """Minimal dispatch-table web app (framework-free for the fixture)."""

    def __init__(self, settings: Settings) -> None:
        self.settings = settings
        self.db = Database(settings.database_path)
        self._routes: dict[tuple[str, str], object] = {}

    def route(self, method: str, path: str, handler) -> None:
        self._routes[(method, path)] = handler

    def dispatch(self, method: str, path: str, payload: dict) -> object:
        handler = self._routes[(method, path)]
        return handler(self.db, payload)


def create_app(config_path: str | None = None) -> App:
    """Build the app: load config, connect the database, register routes."""
    settings = load_config(config_path)
    app = App(settings)
    app.db.connect()
    register_routes(app)
    return app


def run() -> None:
    """Start the server (fixture stub: builds the app and reports readiness)."""
    app = create_app()
    print(f"taskhub listening on {app.settings.host}:{app.settings.port}")

"""SQLite database access layer."""

import sqlite3

_SCHEMA = """
CREATE TABLE IF NOT EXISTS tasks (
    id INTEGER PRIMARY KEY,
    title TEXT NOT NULL,
    status TEXT NOT NULL DEFAULT 'open',
    owner_id INTEGER,
    created_at TEXT NOT NULL
);
CREATE TABLE IF NOT EXISTS users (
    id INTEGER PRIMARY KEY,
    email TEXT UNIQUE NOT NULL,
    name TEXT NOT NULL
);
"""


class Database:
    """Thin wrapper around sqlite3 with row factories."""

    def __init__(self, path: str) -> None:
        self.path = path
        self._conn: sqlite3.Connection | None = None

    def connect(self) -> sqlite3.Connection:
        """Open (and memoize) the database connection, creating the schema."""
        if self._conn is None:
            self._conn = sqlite3.connect(self.path)
            self._conn.row_factory = sqlite3.Row
            self._conn.executescript(_SCHEMA)
        return self._conn

    def execute(self, sql: str, params: tuple = ()) -> sqlite3.Cursor:
        return self.connect().execute(sql, params)

    def fetch_all(self, sql: str, params: tuple = ()) -> list[sqlite3.Row]:
        return self.execute(sql, params).fetchall()

    def close(self) -> None:
        if self._conn is not None:
            self._conn.close()
            self._conn = None

